import{j as a,b as e,c as t,a9 as i}from"./chunks/framework.CFGK5tmi.js";const u=JSON.parse('{"title":"JETBRA系列IDE安装","description":"","frontmatter":{},"headers":[],"relativePath":"backend/environment/jetbra.md","filePath":"backend/environment/jetbra.md","lastUpdated":null}'),n={name:"backend/environment/jetbra.md"},r=i('<h1 id="jetbra系列ide安装" tabindex="-1">JETBRA系列IDE安装 <a class="header-anchor" href="#jetbra系列ide安装" aria-label="Permalink to &quot;JETBRA系列IDE安装&quot;">​</a></h1><p>网站：<a href="https://3.jetbra.in/" target="_blank" rel="noreferrer">https://3.jetbra.in/</a></p><h2 id="一、下载script" tabindex="-1">一、下载script <a class="header-anchor" href="#一、下载script" aria-label="Permalink to &quot;一、下载script&quot;">​</a></h2><p>进入网站，挑选一个可用网站，可能需要多试几次</p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/image-20240524111952303.png" alt="image-20240524111952303"></p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/image-20240530153251312.png" alt="6913c22d9aa36378a528f58394b8bd0f"></p><h2 id="二、install操作" tabindex="-1">二、install操作 <a class="header-anchor" href="#二、install操作" aria-label="Permalink to &quot;二、install操作&quot;">​</a></h2><p>在<code>scripts</code>文件夹下，执行<code>uninstall-current-user.vbs</code>（防止以前用过install操作），再执行<code>install-current-user.vbs</code>，等待done结束即可。</p><h2 id="三、进入ide" tabindex="-1">三、进入ide <a class="header-anchor" href="#三、进入ide" aria-label="Permalink to &quot;三、进入ide&quot;">​</a></h2><p>在提示需要激活的页面，将网站中的active code复制进去即可。</p><h2 id="四、idea的一些使用技巧" tabindex="-1">四、idea的一些使用技巧 <a class="header-anchor" href="#四、idea的一些使用技巧" aria-label="Permalink to &quot;四、idea的一些使用技巧&quot;">​</a></h2><h3 id="maven设置" tabindex="-1">maven设置 <a class="header-anchor" href="#maven设置" aria-label="Permalink to &quot;maven设置&quot;">​</a></h3><p>idea是自带maven的，如果你不设置本地的maven，则会自动使用idea自带的maven，修改maven配置的地方：</p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/6913c22d9aa36378a528f58394b8bd0f.png" alt="image-20240530153251312"></p><h3 id="注释" tabindex="-1">注释 <a class="header-anchor" href="#注释" aria-label="Permalink to &quot;注释&quot;">​</a></h3><p>idea注释的时候，是会从行首开始的，这样当我们代码有缩进的时候，很不方便。以Java为例：点击Editor-&gt;Code Style -&gt; Java，找到 Code Generation，把右下角的设置修改</p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/image-20240530153536238.png" alt="image-20240530153440240"></p><h3 id="忽略大小写提示" tabindex="-1">忽略大小写提示 <a class="header-anchor" href="#忽略大小写提示" aria-label="Permalink to &quot;忽略大小写提示&quot;">​</a></h3><p>在Java中，类一般是大驼峰命名，提示的时候我们也需要使用大小写切换，很不方便。找到Editor-&gt;General-&gt;Code Completion，修改Match-case</p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/image-20240530153440240.png" alt="image-20240530153536238"></p><h3 id="修改ctrl-w快捷键" tabindex="-1">修改Ctrl+w快捷键 <a class="header-anchor" href="#修改ctrl-w快捷键" aria-label="Permalink to &quot;修改Ctrl+w快捷键&quot;">​</a></h3><p>在浏览器中，一般<code>Ctrl+w</code>快捷键是关闭当前标签页，在idea中，关闭的快捷键是<code>Ctrl+F4</code>，很不习惯这个，修改快捷键如下</p><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/environment/image-20240618094735631.png" alt="image-20240618094735631"></p><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTg2NzUyNzkxNTUlN0Q="></div>',24),o=[r];function c(s,d,l,h,m,p){return e(),t("div",null,o)}const b=a(n,[["render",c]]);export{u as __pageData,b as default};
